import React, { useCallback, useMemo, useRef, useState } from 'react';
import { SafeAreaView, View, Text, Pressable, StyleSheet, ActivityIndicator, ScrollView, Alert } from 'react-native';
import * as AuthSession from 'expo-auth-session';
import * as WebBrowser from 'expo-web-browser';
import * as SecureStore from 'expo-secure-store';

WebBrowser.maybeCompleteAuthSession();

const OAUTH_CONFIG = {
  issuer: 'https://YOUR_AUTH_SERVER_DOMAIN',
  authorizationEndpoint: 'https://YOUR_AUTH_SERVER_DOMAIN/oauth2/authorize',
  tokenEndpoint: 'https://YOUR_AUTH_SERVER_DOMAIN/oauth2/token',
  revocationEndpoint: 'https://YOUR_AUTH_SERVER_DOMAIN/oauth2/revoke',
  userInfoEndpoint: 'https://YOUR_AUTH_SERVER_DOMAIN/oauth2/userinfo',
  scopes: ['openid', 'profile', 'email', 'offline_access'],
};

const CLIENT_ID = 'mobile_app_client_123';

const TOKEN_STORAGE_KEY = 'oauth_tokens_v1';

function nowSeconds() {
  return Math.floor(Date.now() / 1000);
}

function safeJsonParse(s) {
  try {
    return JSON.parse(s);
  } catch {
    return null;
  }
}

async function storeTokens(tokens) {
  await SecureStore.setItemAsync(TOKEN_STORAGE_KEY, JSON.stringify(tokens));
}

async function loadTokens() {
  const raw = await SecureStore.getItemAsync(TOKEN_STORAGE_KEY);
  return raw ? safeJsonParse(raw) : null;
}

async function clearTokens() {
  await SecureStore.deleteItemAsync(TOKEN_STORAGE_KEY);
}

function isTokenExpired(tokens, skewSeconds = 30) {
  if (!tokens?.accessToken || !tokens?.expiresAt) return true;
  return tokens.expiresAt <= nowSeconds() + skewSeconds;
}

function buildFormBody(params) {
  const body = [];
  for (const [k, v] of Object.entries(params)) {
    if (v === undefined || v === null) continue;
    body.push(encodeURIComponent(k) + '=' + encodeURIComponent(String(v)));
  }
  return body.join('&');
}

async function fetchJson(url, options) {
  const res = await fetch(url, options);
  const text = await res.text();
  const data = safeJsonParse(text) ?? { raw: text };
  if (!res.ok) {
    const err = new Error(data?.error_description || data?.error || `HTTP ${res.status}`);
    err.status = res.status;
    err.data = data;
    throw err;
  }
  return data;
}

async function exchangeCodeForTokens({
  code,
  redirectUri,
  codeVerifier,
}) {
  // Note: Mobile apps should NOT embed a client_secret. Use PKCE without a secret.
  const body = buildFormBody({
    grant_type: 'authorization_code',
    client_id: CLIENT_ID,
    code,
    redirect_uri: redirectUri,
    code_verifier: codeVerifier,
  });

  const data = await fetchJson(OAUTH_CONFIG.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      Accept: 'application/json',
    },
    body,
  });

  const expiresIn = typeof data.expires_in === 'number' ? data.expires_in : 3600;
  const tokens = {
    tokenType: data.token_type,
    accessToken: data.access_token,
    refreshToken: data.refresh_token,
    idToken: data.id_token,
    scope: data.scope,
    expiresAt: nowSeconds() + expiresIn,
  };

  await storeTokens(tokens);
  return tokens;
}

async function refreshAccessToken(tokens) {
  if (!tokens?.refreshToken) throw new Error('No refresh token available');

  const body = buildFormBody({
    grant_type: 'refresh_token',
    client_id: CLIENT_ID,
    refresh_token: tokens.refreshToken,
  });

  const data = await fetchJson(OAUTH_CONFIG.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      Accept: 'application/json',
    },
    body,
  });

  const expiresIn = typeof data.expires_in === 'number' ? data.expires_in : 3600;

  const updated = {
    ...tokens,
    tokenType: data.token_type ?? tokens.tokenType,
    accessToken: data.access_token ?? tokens.accessToken,
    idToken: data.id_token ?? tokens.idToken,
    scope: data.scope ?? tokens.scope,
    refreshToken: data.refresh_token ?? tokens.refreshToken,
    expiresAt: nowSeconds() + expiresIn,
  };

  await storeTokens(updated);
  return updated;
}

async function revokeToken(token, tokenTypeHint) {
  if (!OAUTH_CONFIG.revocationEndpoint || !token) return;

  const body = buildFormBody({
    token,
    token_type_hint: tokenTypeHint,
    client_id: CLIENT_ID,
  });

  try {
    await fetch(OAUTH_CONFIG.revocationEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body,
    });
  } catch {
    // ignore
  }
}

async function fetchUserInfo(accessToken) {
  if (!OAUTH_CONFIG.userInfoEndpoint) return null;
  return fetchJson(OAUTH_CONFIG.userInfoEndpoint, {
    headers: {
      Authorization: `Bearer ${accessToken}`,
      Accept: 'application/json',
    },
  });
}

export default function App() {
  const redirectUri = useMemo(
    () => AuthSession.makeRedirectUri({ useProxy: true }),
    []
  );

  const discovery = useMemo(
    () => ({
      authorizationEndpoint: OAUTH_CONFIG.authorizationEndpoint,
      tokenEndpoint: OAUTH_CONFIG.tokenEndpoint,
      revocationEndpoint: OAUTH_CONFIG.revocationEndpoint,
    }),
    []
  );

  const [tokens, setTokens] = useState(null);
  const [userInfo, setUserInfo] = useState(null);
  const [busy, setBusy] = useState(false);

  const codeVerifierRef = useRef(null);

  const init = useCallback(async () => {
    const t = await loadTokens();
    if (t) setTokens(t);
  }, []);

  React.useEffect(() => {
    init();
  }, [init]);

  const ensureFreshAccessToken = useCallback(async () => {
    let t = tokens ?? (await loadTokens());
    if (!t) return null;

    if (!isTokenExpired(t)) return t;

    const refreshed = await refreshAccessToken(t);
    setTokens(refreshed);
    return refreshed;
  }, [tokens]);

  const login = useCallback(async () => {
    setBusy(true);
    try {
      const codeVerifier = AuthSession.generateRandom(64);
      const codeChallenge = await AuthSession.generatePKCEAsync(codeVerifier);
      codeVerifierRef.current = codeVerifier;

      const authRequest = new AuthSession.AuthRequest({
        clientId: CLIENT_ID,
        responseType: AuthSession.ResponseType.Code,
        scopes: OAUTH_CONFIG.scopes,
        redirectUri,
        usePKCE: true,
        codeChallenge: codeChallenge.codeChallenge,
        codeChallengeMethod: codeChallenge.codeChallengeMethod,
      });

      const result = await authRequest.promptAsync(discovery, { useProxy: true });

      if (result.type !== 'success') {
        if (result.type === 'error') throw new Error(result.error?.message || 'Authorization error');
        return;
      }

      const code = result.params?.code;
      if (!code) throw new Error('No authorization code returned');

      const exchanged = await exchangeCodeForTokens({
        code,
        redirectUri,
        codeVerifier: codeVerifierRef.current,
      });

      setTokens(exchanged);

      try {
        const ui = await fetchUserInfo(exchanged.accessToken);
        setUserInfo(ui);
      } catch {
        setUserInfo(null);
      }
    } catch (e) {
      Alert.alert('Login failed', e?.message || String(e));
    } finally {
      setBusy(false);
    }
  }, [redirectUri, discovery]);

  const loadProfile = useCallback(async () => {
    setBusy(true);
    try {
      const t = await ensureFreshAccessToken();
      if (!t?.accessToken) throw new Error('Not authenticated');

      const ui = await fetchUserInfo(t.accessToken);
      setUserInfo(ui);
    } catch (e) {
      Alert.alert('Profile error', e?.message || String(e));
    } finally {
      setBusy(false);
    }
  }, [ensureFreshAccessToken]);

  const logout = useCallback(async () => {
    setBusy(true);
    try {
      const t = tokens ?? (await loadTokens());
      if (t?.refreshToken) await revokeToken(t.refreshToken, 'refresh_token');
      if (t?.accessToken) await revokeToken(t.accessToken, 'access_token');
      await clearTokens();
      setTokens(null);
      setUserInfo(null);
    } catch (e) {
      await clearTokens();
      setTokens(null);
      setUserInfo(null);
    } finally {
      setBusy(false);
    }
  }, [tokens]);

  const showTokens = useCallback(async () => {
    const t = tokens ?? (await loadTokens());
    Alert.alert('Tokens', JSON.stringify(t, null, 2).slice(0, 4000));
  }, [tokens]);

  return (
    <SafeAreaView style={styles.root}>
      <View style={styles.header}>
        <Text style={styles.title}>OAuth 2.0 MVP</Text>
        <Text style={styles.subtitle}>Authorization Code + PKCE (mobile-safe)</Text>
      </View>

      <View style={styles.card}>
        <Text style={styles.label}>Redirect URI</Text>
        <Text style={styles.mono} numberOfLines={2}>{redirectUri}</Text>

        <View style={styles.row}>
          <Pressable style={[styles.button, busy && styles.buttonDisabled]} disabled={busy} onPress={login}>
            {busy ? <ActivityIndicator color="#fff" /> : <Text style={styles.buttonText}>Login</Text>}
          </Pressable>

          <Pressable style={[styles.buttonSecondary, busy && styles.buttonDisabled]} disabled={busy} onPress={logout}>
            <Text style={styles.buttonTextSecondary}>Logout</Text>
          </Pressable>
        </View>

        <View style={styles.row}>
          <Pressable style={[styles.buttonSecondary, busy && styles.buttonDisabled]} disabled={busy} onPress={loadProfile}>
            <Text style={styles.buttonTextSecondary}>Load Profile</Text>
          </Pressable>

          <Pressable style={[styles.buttonSecondary, busy && styles.buttonDisabled]} disabled={busy} onPress={showTokens}>
            <Text style={styles.buttonTextSecondary}>Show Tokens</Text>
          </Pressable>
        </View>
      </View>

      <ScrollView style={styles.card} contentContainerStyle={{ paddingBottom: 24 }}>
        <Text style={styles.sectionTitle}>Session</Text>
        <Text style={styles.label}>Authenticated</Text>
        <Text style={styles.value}>{tokens?.accessToken ? 'Yes' : 'No'}</Text>

        <Text style={styles.label}>Access Token Expires</Text>
        <Text style={styles.value}>
          {tokens?.expiresAt ? new Date(tokens.expiresAt * 1000).toISOString() : '—'}
        </Text>

        <Text style={styles.sectionTitle}>User Info</Text>
        <Text style={styles.mono}>{userInfo ? JSON.stringify(userInfo, null, 2) : '—'}</Text>
      </ScrollView>
    </SafeAreaView>
  );
}

